import React, { useEffect, useRef, useState } from 'react';
import './FloatingLines.css';

const FloatingLines = ({
  linesGradient = ['#2F4BC0', '#8000ff'],
  animationSpeed = 1,
  interactive = true,
  bendRadius = 5,
  bendStrength = -0.5,
  mouseDamping = 0.05,
  parallax = true,
  parallaxStrength = 0.2,
}) => {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const linesRef = useRef([]);
  const animationIdRef = useRef(null);
  const timeRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    
    if (!canvas || !container) return;

    const ctx = canvas.getContext('2d');
    
    // Set canvas size to match container
    const resizeCanvas = () => {
      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    };
    
    resizeCanvas();

    // Initialize lines
    const initLines = () => {
      linesRef.current = [];
      const lineCount = 6;
      
      for (let i = 0; i < lineCount; i++) {
        linesRef.current.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * animationSpeed,
          vy: (Math.random() - 0.5) * animationSpeed,
          length: 60 + Math.random() * 120,
          angle: Math.random() * Math.PI * 2,
          angularVelocity: (Math.random() - 0.5) * 0.05 * animationSpeed,
        });
      }
    };

    initLines();

    const getGradientColor = (index) => {
      return linesGradient[index % linesGradient.length];
    };

    const drawLine = (line, index) => {
      const x = line.x;
      const y = line.y;
      const angle = line.angle;
      const length = line.length;

      const x1 = x - Math.cos(angle) * (length / 2);
      const y1 = y - Math.sin(angle) * (length / 2);
      const x2 = x + Math.cos(angle) * (length / 2);
      const y2 = y + Math.sin(angle) * (length / 2);

      // Get color
      const color = getGradientColor(index);

      // Draw glowing line effect
      // Outer glow
      ctx.strokeStyle = color;
      ctx.lineWidth = 8;
      ctx.globalAlpha = 0.2;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';

      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      // Middle glow
      ctx.lineWidth = 4;
      ctx.globalAlpha = 0.4;

      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      // Main line (bright)
      ctx.lineWidth = 2;
      ctx.globalAlpha = 1;

      ctx.beginPath();
      ctx.moveTo(x1, y1);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      ctx.globalAlpha = 1;
    };

    const animate = () => {
      timeRef.current += animationSpeed * 0.016;

      // Clear canvas with very light fade for trail effect
      ctx.fillStyle = 'rgba(0, 0, 0, 0.1)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Update and draw lines
      linesRef.current.forEach((line, index) => {
        // Update angle
        line.angularVelocity += (Math.random() - 0.5) * 0.01 * animationSpeed;
        line.angle += line.angularVelocity;

        // Apply velocity
        line.x += line.vx * animationSpeed;
        line.y += line.vy * animationSpeed;

        // Wrap around edges with padding
        const padding = 100;
        if (line.x < -padding) line.x = canvas.width + padding;
        if (line.x > canvas.width + padding) line.x = -padding;
        if (line.y < -padding) line.y = canvas.height + padding;
        if (line.y > canvas.height + padding) line.y = -padding;

        // Apply damping to velocity
        line.vx *= 0.99;
        line.vy *= 0.99;

        // Interactive mouse response
        if (interactive && mousePos) {
          const dx = mousePos.x - line.x;
          const dy = mousePos.y - line.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const maxDistance = bendRadius * 50; // Scale bendRadius

          if (distance < maxDistance && distance > 0) {
            const angle = Math.atan2(dy, dx);
            const force = (1 - distance / maxDistance) * Math.abs(bendStrength);
            
            if (bendStrength < 0) {
              // Repulsion (negative bendStrength)
              line.vx -= Math.cos(angle) * force * mouseDamping;
              line.vy -= Math.sin(angle) * force * mouseDamping;
            } else {
              // Attraction (positive bendStrength)
              line.vx += Math.cos(angle) * force * mouseDamping;
              line.vy += Math.sin(angle) * force * mouseDamping;
            }
          }
        }

        // Parallax effect
        if (parallax) {
          line.x += Math.sin(timeRef.current * 0.5 + index) * parallaxStrength * animationSpeed;
          line.y += Math.cos(timeRef.current * 0.5 + index) * parallaxStrength * animationSpeed;
        }

        drawLine(line, index);
      });

      animationIdRef.current = requestAnimationFrame(animate);
    };

    animate();

    // Handle mouse move
    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      setMousePos({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      });
    };

    // Handle mouse leave
    const handleMouseLeave = () => {
      setMousePos({ x: canvas.width / 2, y: canvas.height / 2 });
    };

    if (interactive) {
      canvas.addEventListener('mousemove', handleMouseMove);
      container.addEventListener('mouseleave', handleMouseLeave);
    }

    // Handle window resize
    const handleResize = () => {
      resizeCanvas();
      initLines();
    };

    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animationIdRef.current);
      if (interactive) {
        canvas.removeEventListener('mousemove', handleMouseMove);
        container.removeEventListener('mouseleave', handleMouseLeave);
      }
      window.removeEventListener('resize', handleResize);
    };
  }, [linesGradient, animationSpeed, interactive, bendRadius, bendStrength, mouseDamping, parallax, parallaxStrength, mousePos]);

  return (
    <div ref={containerRef} className="floating-lines-container">
      <canvas
        ref={canvasRef}
        className="floating-lines-canvas"
      />
    </div>
  );
};

export default FloatingLines;
